TOKEN_SECRET = os.getenv("TOKEN_SECRET", secrets.token_hex(32))

redis_client: Optional[redis.Redis] = None

security = HTTPBearer()


async def get_redis_client() -> redis.Redis:
    global redis_client
    if redis_client is None:
        redis_client = redis.Redis(
            host=REDIS_HOST,
            port=REDIS_PORT,
            db=REDIS_DB,
            password=REDIS_PASSWORD,
            decode_responses=True,
            socket_connect_timeout=5,
            socket_keepalive=True,
        )
    return redis_client


def constant_time_compare(val1: str, val2: str) -> bool:
    return hmac.compare_digest(val1, val2)


def hash_token(token: str) -> str:
    return hashlib.sha256(token.encode()).hexdigest()


def verify_token_signature(token: str) -> bool:
    try:
        if "." not in token:
            return False
        
        parts = token.split(".")
        if len(parts) != 2:
            return False
        
        token_data, signature = parts
        expected_signature = hmac.new(
            TOKEN_SECRET.encode(),
            token_data.encode(),
            hashlib.sha256
        ).hexdigest()
        
        return constant_time_compare(signature, expected_signature)
    except Exception:
        return False


async def validate_token_rate_limit(
    token_hash: str,
    redis_conn: redis.Redis,
    max_requests: int = 100,
    window_seconds: int = 60
) -> bool:
    rate_limit_key = f"rate_limit:{token_hash}"
    
    current_count = await redis_conn.get(rate_limit_key)
    
    if current_count is None:
        await redis_conn.setex(rate_limit_key, window_seconds, 1)
        return True
    
    if int(current_count) >= max_requests:
        return False
    
    await redis_conn.incr(rate_limit_key)
    return True


async def validate_token_metadata(
    token_data: dict,
    redis_conn: redis.Redis
) -> bool:
    if "exp" in token_data:
        exp_timestamp = token_data["exp"]
        if datetime.utcnow().timestamp() > exp_timestamp:
            return False
    
    if "scope" in token_data:
        required_scopes = token_data.get("required_scopes", [])
        token_scopes = token_data["scope"]
        if not all(scope in token_scopes for scope in required_scopes):
            return False
    
    if "ip_whitelist" in token_data:
        return True
    
    return True


async def validate_bearer_token(
    credentials: HTTPAuthorizationCredentials = Depends(security),
    redis_conn: redis.Redis = Depends(get_redis_client),
    x_forwarded_for: Optional[str] = Header(None),
    user_agent: Optional[str] = Header(None)
) -> dict:
    token = credentials.credentials
    
    if not token or len(token) < 32:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid token format",
            headers={"WWW-Authenticate": "Bearer"},
        )
    
    if not verify_token_signature(token):
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid token signature",
            headers={"WWW-Authenticate": "Bearer"},
        )
    
    token_hash = hash_token(token)
    
    token_key = f"token:{token_hash}"
    token_data_str = await redis_conn.get(token_key)
    
    if not token_data_str:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Token not found or expired",
            headers={"WWW-Authenticate": "Bearer"},
        )
    
    try:
        token_data = json.loads(token_data_str)
    except json.JSONDecodeError:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid token data",
            headers={"WWW-Authenticate": "Bearer"},
        )
    
    if not await validate_token_metadata(token_data, redis_conn):
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Token validation failed",
            headers={"WWW-Authenticate": "Bearer"},
        )
    
    if not await validate_token_rate_limit(token_hash, redis_conn):
        raise HTTPException(
            status_code=status.HTTP_429_TOO_MANY_REQUESTS,
            detail="Rate limit exceeded",
        )
    
    revocation_key = f"revoked:{token_hash}"
    is_revoked = await redis_conn.exists(revocation_key)
    if is_revoked:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Token has been revoked",
            headers={"WWW-Authenticate": "Bearer"},
        )
    
    if "ip_whitelist" in token_data and x_forwarded_for:
        client_ip = x_forwarded_for.split(",")[0].strip()
        if client_ip not in token_data["ip_whitelist"]:
            raise HTTPException(
                status_code=status.HTTP_403_FORBIDDEN,
                detail="IP address not whitelisted",
            )
    
    last_used_key = f"last_used:{token_hash}"
    await redis_conn.setex(last_used_key, 86400, datetime.utcnow().isoformat())
    
    return token_data


async def validate_bearer_token_with_scope(required_scope: str):
    async def scope_validator(
        token_data: dict = Depends(validate_bearer_token)
    ) -> dict:
        token_scopes = token_data.get("scope", [])
        if required_scope not in token_scopes:
            raise HTTPException(
                status_code=status.HTTP_403_FORBIDDEN,
                detail=f"Insufficient scope. Required: {required_scope}",
            )
        return token_data
    
    return scope_validator


@app.on_event("startup")
async def startup_event():
    global redis_client
    redis_client = await get_redis_client()
    await redis_client.ping()


@app.on_event("shutdown")
async def shutdown_event():
    if redis_client:
        await redis_client.close()


