@app.post("/token/create")
async def create_token(
    user_id: str,
    scopes: list[str],
    ttl: int = 3600,
    redis_conn: redis.Redis = Depends(get_redis_client)
):
    token_data_part = secrets.token_urlsafe(32)
    signature = hmac.new(
        TOKEN_SECRET.encode(),
        token_data_part.encode(),
        hashlib.sha256
    ).hexdigest()
    
    token = f"{token_data_part}.{signature}"
    token_hash = hash_token(token)
    
    token_metadata = {
        "user_id": user_id,
        "scope": scopes,
        "exp": (datetime.utcnow() + timedelta(seconds=ttl)).timestamp(),
        "created_at": datetime.utcnow().isoformat()
    }
    
    token_key = f"token:{token_hash}"
    await redis_conn.setex(
        token_key,
        ttl,
        json.dumps(token_metadata)
    )
    
    return {
        "access_token": token,
        "token_type": "bearer",
        "expires_in": ttl
    }


@app.post("/token/revoke")
async def revoke_token(
    token_data: dict = Depends(validate_bearer_token),
    credentials: HTTPAuthorizationCredentials = Depends(security),
    redis_conn: redis.Redis = Depends(get_redis_client)
):
    token = credentials.credentials
    token_hash = hash_token(token)
    
    revocation_key = f"revoked:{token_hash}"
    await redis_conn.setex(revocation_key, 86400, "1")
    
    token_key = f"token:{token_hash}"
    await redis_conn.delete(token_key)
    
    return {"message": "Token revoked successfully"}


